import{bQ as d,aL as r,u as a,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"选型常识","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/16-选型常识.md","filePath":"00.互联网与架构基础/16-选型常识.md","lastUpdated":null}'),h={name:"00.互联网与架构基础/16-选型常识.md"};function o(p,t,i,l,n,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="选型常识" tabindex="-1">选型常识 <a class="header-anchor" href="#选型常识" aria-label="Permalink to &quot;选型常识&quot;">​</a></h1><p>选技术时，很容易被框架名字、性能排行、流行趋势带着走。真正落到系统里，更常见的问题是：团队会不会用，出了故障能不能查，数据能不能恢复，后面能不能升级和迁移。</p><p>一个组件进入系统以后，就会带来部署、监控、备份、权限、升级、安全漏洞、故障处理和人员交接。选型要同时看当前问题和后续维护。</p><h2 id="一、先看问题" tabindex="-1">一、先看问题 <a class="header-anchor" href="#一、先看问题" aria-label="Permalink to &quot;一、先看问题&quot;">​</a></h2><p>选型前要先知道问题是什么。</p><table tabindex="0"><thead><tr><th>问题</th><th>可能对应的组件</th></tr></thead><tbody><tr><td>接口重复查询太多</td><td>缓存</td></tr><tr><td>后台任务耗时长</td><td>消息队列、任务调度</td></tr><tr><td>文件需要多实例共享</td><td>对象存储、共享存储</td></tr><tr><td>服务实例经常变化</td><td>服务发现、负载均衡</td></tr><tr><td>发布容易出错</td><td>CI/CD、镜像、GitOps</td></tr><tr><td>故障不知道在哪</td><td>指标、日志、链路追踪</td></tr></tbody></table><p>如果问题只是单表查询慢，第一步通常是看 SQL、索引和数据量，还不到立刻上分库分表的程度。如果只是内部低频任务，普通定时任务可能已经够用，也不到马上引入复杂调度平台的程度。</p><h2 id="二、简单一点" tabindex="-1">二、简单一点 <a class="header-anchor" href="#二、简单一点" aria-label="Permalink to &quot;二、简单一点&quot;">​</a></h2><p>这里的简单指路径短、状态少、团队能理解。一个系统里少一个组件，就少一类故障、日志、权限和升级工作。</p><p>简单方案通常有几个特点：</p><table tabindex="0"><thead><tr><th>特点</th><th>表现</th></tr></thead><tbody><tr><td>链路短</td><td>请求经过的组件少</td></tr><tr><td>状态清楚</td><td>数据存在哪里能说清</td></tr><tr><td>恢复直接</td><td>出故障有明确回滚和恢复方式</td></tr><tr><td>人员可接手</td><td>新同事能通过文档和日志理解</td></tr></tbody></table><p>复杂方案也有价值，但最好是被真实问题推出来。没有明显读压力时上读写分离，没有多团队协作时拆十几个微服务，最后可能只是把简单问题变成复杂系统。</p><h2 id="三、稳定和生态" tabindex="-1">三、稳定和生态 <a class="header-anchor" href="#三、稳定和生态" aria-label="Permalink to &quot;三、稳定和生态&quot;">​</a></h2><p>数据库、消息队列、监控、网关这类组件一旦进入核心链路，替换成本很高。基础组件更看重稳定、生态和维护周期。</p><p>选组件时常见观察点：</p><table tabindex="0"><thead><tr><th>观察点</th><th>含义</th></tr></thead><tbody><tr><td>社区和厂商</td><td>是否有人持续维护</td></tr><tr><td>文档和案例</td><td>出问题时能否查到资料</td></tr><tr><td>版本节奏</td><td>升级是否频繁破坏兼容</td></tr><tr><td>生态适配</td><td>是否能接入现有监控、认证、部署体系</td></tr><tr><td>运维工具</td><td>是否有备份、恢复、迁移、诊断工具</td></tr></tbody></table><p>小众组件可以用，但要承担资料少、故障案例少、招聘和交接困难的成本。核心数据链路上尤其要谨慎。</p><h2 id="四、团队会不会维护" tabindex="-1">四、团队会不会维护 <a class="header-anchor" href="#四、团队会不会维护" aria-label="Permalink to &quot;四、团队会不会维护&quot;">​</a></h2><p>团队熟悉程度很重要。一个团队主要写 Python，内部平台用 FastAPI 很自然；团队长期维护 Java 微服务，Spring Boot 生态可能更稳；云原生组件用 Go 写得多，Go 在运维开发里也常见。</p><p>语言和框架要考虑：</p><table tabindex="0"><thead><tr><th>维度</th><th>问题</th></tr></thead><tbody><tr><td>开发效率</td><td>写一个功能要多久</td></tr><tr><td>运行方式</td><td>部署、配置、日志是否清楚</td></tr><tr><td>性能要求</td><td>当前瓶颈是否在语言和运行时</td></tr><tr><td>人员储备</td><td>团队是否有人能排查线上问题</td></tr><tr><td>生态依赖</td><td>数据库、认证、监控、测试是否成熟</td></tr></tbody></table><p>一门语言能做很多事，但团队不熟悉时，线上故障会暴露得很快。能写出来和能维护三年，是两件事。</p><h2 id="五、出问题看哪里" tabindex="-1">五、出问题看哪里 <a class="header-anchor" href="#五、出问题看哪里" aria-label="Permalink to &quot;五、出问题看哪里&quot;">​</a></h2><p>组件进入生产前，要知道它出问题时看哪里。</p><table tabindex="0"><thead><tr><th>组件</th><th>至少要有的排查入口</th></tr></thead><tbody><tr><td>Nginx</td><td>access log、error log、upstream 状态</td></tr><tr><td>数据库</td><td>慢日志、连接数、锁等待、备份状态</td></tr><tr><td>Redis</td><td>内存、连接、慢查询、key 过期策略</td></tr><tr><td>消息队列</td><td>积压、消费失败、重试、死信</td></tr><tr><td>Kubernetes</td><td>Pod 状态、Events、日志、Service、Ingress</td></tr><tr><td>CI/CD</td><td>构建日志、制品版本、发布记录</td></tr></tbody></table><p>没有日志、没有指标、没有备份、没有恢复文档的组件，功能再好也很难放进关键链路。出了问题只能猜，故障时间会被拉长。</p><h2 id="六、以后能不能退出" tabindex="-1">六、以后能不能退出 <a class="header-anchor" href="#六、以后能不能退出" aria-label="Permalink to &quot;六、以后能不能退出&quot;">​</a></h2><p>选型还要看退出路径。数据能不能导出，配置能不能迁移，协议是否通用，是否强绑定某个云厂商或平台。</p><p>常见风险：</p><table tabindex="0"><thead><tr><th>风险</th><th>表现</th></tr></thead><tbody><tr><td>数据格式封闭</td><td>想迁移时导不出完整数据</td></tr><tr><td>API 强绑定</td><td>换平台要大改代码</td></tr><tr><td>配置不可复制</td><td>只能在控制台点，无法版本化</td></tr><tr><td>成本不可控</td><td>流量、存储、调用次数增长后费用暴涨</td></tr><tr><td>升级困难</td><td>老版本不兼容，新版本迁移路径复杂</td></tr></tbody></table><p>完全避免绑定不现实，但关键数据和核心链路要知道绑定在哪里，以及未来迁移要付出什么代价。</p><h2 id="七、常见组合" tabindex="-1">七、常见组合 <a class="header-anchor" href="#七、常见组合" aria-label="Permalink to &quot;七、常见组合&quot;">​</a></h2><p>内部运维平台可以从比较稳的组合开始：前端用 Vue 或 React，后端用 Python FastAPI、Go 或 Java Spring Boot，数据库用 PostgreSQL 或 MySQL，缓存用 Redis，文件放对象存储，入口用 Nginx 或 Ingress，指标用 Prometheus，日志接 Loki 或 OpenSearch。</p><p>这组只是常见组合。更重要的是每一层都有明确位置：前端负责页面，后端负责接口，数据库保存状态，缓存加速热点，消息队列处理异步任务，入口层接收流量，监控和日志负责看见系统状态。</p><p>选型最后回到几个朴素问题：它解决的具体问题是什么，团队是否会维护，故障是否能排查，数据是否能恢复，未来是否能迁移。</p>',35)])])}const u=d(h,[["render",o]]);export{c as __pageData,u as default};
